const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const rawQuestion = typeof payload.question === 'string' ? payload.question : (typeof payload.message === 'string' ? payload.message : payload.query);
const rawProjectSlug = payload.project_slug;
const rawSessionId = payload.session_id;

const buildError = (code, message) => [{
  json: {
    ok: false,
    question: null,
    project_slug: 'alpha',
    answer: null,
    sources: [],
    error: { code, message },
    debug: {
      workflow: 'crispybrain-demo',
      upstream_workflow: 'assistant',
      teacher_used: false,
      retrieval_count: 0,
      defaulted_project_slug: true,
      session_id: null
    }
  }
}];

if (typeof rawQuestion !== 'string' || rawQuestion.trim() === '') {
  return buildError('INVALID_QUESTION', 'Please enter a question before submitting the demo.');
}

if (rawProjectSlug !== undefined && rawProjectSlug !== null && typeof rawProjectSlug !== 'string') {
  return buildError('INVALID_PROJECT_SLUG', 'project_slug must be a string when provided.');
}

if (rawSessionId !== undefined && rawSessionId !== null && typeof rawSessionId !== 'string') {
  return buildError('INVALID_SESSION_ID', 'session_id must be a string when provided.');
}

const trimmedProjectSlug = typeof rawProjectSlug === 'string' ? rawProjectSlug.trim() : '';
const projectSlug = trimmedProjectSlug || 'alpha';
const sessionId = typeof rawSessionId === 'string' && rawSessionId.trim() !== ''
  ? rawSessionId.trim()
  : `crispybrain-demo-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

return [{
  json: {
    request_ok: true,
    question: rawQuestion.trim(),
    project_slug: projectSlug,
    session_id: sessionId,
    defaulted_project_slug: trimmedProjectSlug === ''
  }
}];

const request = $('Normalize Demo Request').first().json;
const statusCode = $json.statusCode ?? 0;
const body = $json.body ?? {};
const sources = Array.isArray(body.sources) ? body.sources : [];
const workflowChain = Array.isArray(body.trace?.workflow_chain) ? body.trace.workflow_chain : [];
const debug = {
  workflow: 'crispybrain-demo',
  upstream_workflow: 'assistant',
  teacher_used: workflowChain.includes('crispybrain-answer-from-memory') || (typeof body.answer === 'string' && body.answer.trim() !== ''),
  retrieval_count: Number(body.retrieval?.memory_count ?? sources.length ?? 0),
  defaulted_project_slug: request.defaulted_project_slug === true,
  session_id: body.session_id ?? request.session_id,
  upstream_status: statusCode || null,
  trace_stage: body.trace?.stage ?? null
};

if (statusCode < 200 || statusCode >= 300) {
  return [{
    json: {
      ok: false,
      question: request.question,
      project_slug: request.project_slug,
      answer: null,
      sources: [],
      error: {
        code: 'UPSTREAM_HTTP_ERROR',
        message: 'The CrispyBrain demo workflow could not reach the assistant path successfully.',
        status: statusCode || null
      },
      debug
    }
  }];
}

if (body.ok !== true) {
  return [{
    json: {
      ok: false,
      question: request.question,
      project_slug: request.project_slug,
      answer: typeof body.answer === 'string' && body.answer.trim() ? body.answer : null,
      sources,
      error: body.error ?? {
        code: 'UPSTREAM_DEMO_FAILURE',
        message: 'The CrispyBrain assistant did not return a successful answer.'
      },
      debug: {
        ...debug,
        retrieval_empty: body.retrieval?.empty === true
      }
    }
  }];
}

return [{
  json: {
    ok: true,
    question: request.question,
    project_slug: body.project_slug ?? request.project_slug,
    answer: body.answer,
    sources,
    debug
  }
}];
